function ProgressBar({ value, max = 100, width = 30, label, showPercent = true }) {
  const { div, span } = tags;
  const pct = Math.round((value / max) * 100);
  const filled = Math.round((value / max) * width);
  const empty = width - filled;
  const bar = '█'.repeat(filled) + '░'.repeat(empty);

  return div({ class: css('_flex _aic _gap2 _mono') },
    label ? span({ class: css('_w[100px] _truncate') }, label) : null,
    span({}, `[${bar}]`),
    showPercent ? span({ class: css('_w[40px] _textright') }, `${pct}%`) : null
  );
}

