import { tags } from 'decantr/tags';
import { createSignal, onMount, onDestroy } from 'decantr/state';
import { css } from 'decantr/css';

code.example:
function Spinner({ label, speed = 80 }) {
  const { div, span } = tags;
  const frames = ['⠋', '⠙', '⠹', '⠸', '⠼', '⠴', '⠦', '⠧', '⠇', '⠏'];
  const [frame, setFrame] = createSignal(0);

  onMount(() => {
    const interval = setInterval(() => setFrame((frame() + 1) % frames.length), speed);
    return () => clearInterval(interval);
  });

  return div({ class: css('_flex _aic _gap2 _mono') },
    span({ class: css('term-glow') }, () => frames[frame()]),
    label ? span({}, label) : null
  );
}

