function DotsProgress({ label, maxDots = 3, speed = 500 }) {
  const { div, span } = tags;
  const [dots, setDots] = createSignal(1);

  onMount(() => {
    const interval = setInterval(() => setDots((dots() % maxDots) + 1), speed);
    return () => clearInterval(interval);
  });

  return div({ class: css('_flex _aic _mono') },
    span({}, label),
    span({ class: css('_w[30px]') }, () => '.'.repeat(dots()))
  );
}

function BlockProgress({ value, max = 100, width = 20 }) {
  const { div, span } = tags;
  const blocks = ['▏', '▎', '▍', '▌', '▋', '▊', '▉', '█'];
  const totalBlocks = width * 8;
  const filledBlocks = Math.round((value / max) * totalBlocks);

  let bar = '';
  const fullChars = Math.floor(filledBlocks / 8);
  const partialIdx = filledBlocks % 8;
  const emptyChars = width - fullChars - (partialIdx > 0 ? 1 : 0);

  bar += '█'.repeat(fullChars);
  if (partialIdx > 0) bar += blocks[partialIdx - 1];
  bar += ' '.repeat(emptyChars);

  return div({ class: css('_flex _aic _gap2 _mono') },
    span({ class: css('_bgmuted/20 _px1') }, bar),
    span({}, `${Math.round((value / max) * 100)}%`)
  );
}

function Progress({ type = 'bar', ...props }) {
  switch (type) {
    case 'spinner': return Spinner(props);
    case 'dots': return DotsProgress(props);
    case 'blocks': return BlockProgress(props);
    default: return ProgressBar(props);
  }
}
